<template><el-card><template #header>元数据管理</template><PageToolbar><el-input v-model="q" placeholder="搜索文号/业务域"/><template #actions><el-button @click="autoFill">AI 自动提取</el-button><el-button type="primary" @click="ElMessage.success('元数据已保存')">保存</el-button></template></PageToolbar><DataTable :data="rows"><el-table-column v-for="c in cols" :key="c.prop" :prop="c.prop" :label="c.label" :min-width="c.width||120"><template #default="s"><el-input v-model="s.row[c.prop]" size="small"/></template></el-table-column></DataTable></el-card></template>
<script setup lang="ts">import { ref } from 'vue'; import { ElMessage } from 'element-plus'; import { metadata } from '@/mock/data'; import PageToolbar from '@/components/PageToolbar.vue'; import DataTable from '@/components/DataTable.vue'; const q=ref(''); const rows=ref<any[]>(JSON.parse(JSON.stringify(metadata))); const cols=[['docNo','文号',160],['publisher','发布单位'],['publishDate','发布日期'],['effectiveDate','生效日期'],['expireDate','失效日期'],['region','适用区域'],['domain','业务域'],['level','政策层级'],['security','安全等级'],['department','归属部门']].map(([prop,label,width])=>({prop,label,width})); function autoFill(){rows.value.forEach(r=>{r.security=r.security||'内部'; r.department=r.department||'营销部'}); ElMessage.success('已模拟 AI 自动提取并批量补全')}</script>
